import json
import sys

def validate_inputs(raw_leads_data, budget_threshold, source_criteria, timeout_duration):
    errors = []

    if not raw_leads_data:
        errors.append("原始线索数据不能为空")

    try:
        budget = float(budget_threshold)
        if budget <= 0:
            errors.append("预算阈值必须大于0")
    except:
        errors.append("预算阈值必须是有效数字")

    if not source_criteria or source_criteria.strip() == "":
        errors.append("来源分流标准不能为空")

    if timeout_duration:
        try:
            timeout = float(timeout_duration)
            if timeout <= 0:
                errors.append("超时时长必须大于0")
        except:
            errors.append("超时时长必须是有效数字")

    return {
        "is_valid": len(errors) == 0,
        "errors": errors,
        "budget_threshold": float(budget_threshold) if budget_threshold else 0,
        "timeout_duration": float(timeout_duration) if timeout_duration else 72
    }

import pandas as pd
import json
import re

def clean_leads_data(raw_data):
    try:
        # 假设原始数据是CSV格式
        df = pd.read_csv(raw_data)

        # 清洗步骤
        # 1. 去除重复记录
        df = df.drop_duplicates()

        # 2. 标准化电话号码格式
        if 'phone' in df.columns:
            df['phone'] = df['phone'].astype(str).apply(lambda x: re.sub(r'[^0-9]', '', x))

        # 3. 标准化邮箱格式
        if 'email' in df.columns:
            df['email'] = df['email'].astype(str).str.lower()

        # 4. 处理缺失值
        numeric_cols = df.select_dtypes(include=['int64', 'float64']).columns
        for col in numeric_cols:
            df[col] = df[col].fillna(df[col].median())

        text_cols = df.select_dtypes(include=['object']).columns
        for col in text_cols:
            df[col] = df[col].fillna('')

        # 5. 添加清洗标记
        df['cleaned_at'] = pd.Timestamp.now().isoformat()
        df['cleaning_status'] = 'success'

        return {
            "status": "success",
            "cleaned_data": df.to_dict('records'),
            "record_count": len(df),
            "cleaning_summary": {
                "duplicates_removed": "自动处理",
                "format_standardized": "电话号码和邮箱已标准化",
                "missing_handled": "数值型用中位数填充，文本型用空字符串填充"
            }
        }
    except Exception as e:
        return {
            "status": "error",
            "error": str(e),
            "cleaned_data": [],
            "record_count": 0
        }

