import json
from datetime import datetime

def format_final_output(report_data):
    try:
        # 解析LLM生成的报告
        if isinstance(report_data, str):
            report = json.loads(report_data)
        else:
            report = report_data

        # 确保输出合约格式
        final_output = {
            "converted_opportunities": report.get("converted_opportunities", []),
            "defeated_archives": report.get("defeated_archives", []),
            "nurturing_leads": report.get("nurturing_leads", []),
            "processing_report": report.get("processing_report", {})
        }

        # 添加时间戳
        final_output["processing_report"]["generated_at"] = datetime.now().isoformat()

        # 验证数据完整性
        for key in ["converted_opportunities", "defeated_archives", "nurturing_leads"]:
            if not isinstance(final_output[key], list):
                final_output[key] = []

        if not isinstance(final_output["processing_report"], dict):
            final_output["processing_report"] = {"error": "报告格式无效"}

        return {
            "status": "success",
            "formatted_output": final_output,
            "output_summary": {
                "opportunities_count": len(final_output["converted_opportunities"]),
                "nurturing_count": len(final_output["nurturing_leads"]),
                "archived_count": len(final_output["defeated_archives"])
            }
        }
    except Exception as e:
        return {
            "status": "error",
            "error": str(e),
            "formatted_output": {
                "converted_opportunities": [],
                "defeated_archives": [],
                "nurturing_leads": [],
                "processing_report": {"error": "输出格式化失败: " + str(e)}
            }
        }
